// ── CSS Keyframes (injected once) ─────────────────────────────────────────────

const KEYFRAMES_ID = 'vouchers-dark-keyframes'
if (typeof document !== 'undefined' && !document.getElementById(KEYFRAMES_ID)) {
  const style = document.createElement('style')
  style.id = KEYFRAMES_ID
  style.textContent = `
    @keyframes vch-float1 {
      0%, 100% { transform: translate(0, 0) scale(1); }
      33% { transform: translate(30px, -40px) scale(1.1); }
      66% { transform: translate(-20px, 20px) scale(0.95); }
    }
    @keyframes vch-float2 {
      0%, 100% { transform: translate(0, 0) scale(1); }
      33% { transform: translate(-40px, 30px) scale(1.05); }
      66% { transform: translate(25px, -25px) scale(0.9); }
    }
    @keyframes vch-float3 {
      0%, 100% { transform: translate(0, 0) scale(1); }
      50% { transform: translate(35px, 35px) scale(1.08); }
    }
    @keyframes vch-fadeUp {
      from { opacity: 0; transform: translateY(16px); }
      to { opacity: 1; transform: translateY(0); }
    }
    @keyframes vch-modalIn {
      from { opacity: 0; transform: scale(0.95) translateY(20px); }
      to { opacity: 1; transform: scale(1) translateY(0); }
    }
    @keyframes vch-shimmer {
      0% { background-position: -200% 0; }
      100% { background-position: 200% 0; }
    }
    @keyframes vch-pulse {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.6; }
    }
    @keyframes vch-overlayIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    /* Card tab — Emil polish */
    .cd-press { transition: transform 160ms cubic-bezier(0.23,1,0.32,1); }
    .cd-press:active { transform: scale(0.97); }
    .cd-card {
      transform: translateZ(0);
    }
    @media (hover: hover) and (pointer: fine) {
      .cd-card:hover {
        transform: translateY(-4px) rotate(-0.4deg);
        box-shadow: 0 22px 50px rgba(0,0,0,0.45), 0 6px 18px rgba(0,0,0,0.35), inset 0 1px 0 rgba(255,255,255,0.22), inset 0 -1px 0 rgba(0,0,0,0.3) !important;
      }
      .cd-card:active { transform: translateY(-2px) scale(0.99); }
    }
    @media (prefers-reduced-motion: reduce) {
      .cd-press, .cd-card { transition: none !important; animation: none !important; }
      .cd-card:hover { transform: none !important; }
    }
  `
  document.head.appendChild(style)
}

// ── Helpers ────────────────────────────────────────────────────────────────────

const SPRING = 'cubic-bezier(0.23,1,0.32,1)'

const expiryStatus = (dateStr) => {
  if (!dateStr) return { color: '#8a837a', bg: 'rgba(138,131,122,0.1)', label: 'ללא תוקף', urgent: false }
  const days = Math.ceil((new Date(dateStr) - new Date()) / 86_400_000)
  if (days < 0)   return { color: '#f87171', bg: 'rgba(248,113,113,0.12)', label: `פג תוקף לפני ${-days} ימים`, urgent: true }
  if (days === 0) return { color: '#f87171', bg: 'rgba(248,113,113,0.12)', label: 'פג תוקף היום!', urgent: true }
  if (days <= 14) return { color: '#f87171', bg: 'rgba(248,113,113,0.12)', label: `${days} ימים נותרו`, urgent: true }
  if (days <= 60) return { color: '#fbbf24', bg: 'rgba(251,191,36,0.12)', label: `${days} ימים · ${fmtDate(dateStr)}`, urgent: true }
  return { color: '#34d399', bg: 'rgba(52,211,153,0.12)', label: fmtDate(dateStr), urgent: false }
}

const fmtDate = (s) =>
  s ? new Date(s).toLocaleDateString('he-IL', { day: '2-digit', month: '2-digit', year: '2-digit' }) : '—'

const fmtMoney = (n, currency) => {
  if (n == null || n === '') return null
  const num = Number(n).toLocaleString('he-IL')
  if (currency === 'USD') return `$${num}`
  return `₪${num}`
}

const fmtDateTime = (iso) =>
  iso ? new Date(iso).toLocaleString('he-IL', {
    day: '2-digit', month: '2-digit', year: '2-digit',
    hour: '2-digit', minute: '2-digit',
  }) : '—'

const storesToArr = (s) =>
  Array.isArray(s) ? s : (s || '').split(',').map(x => x.trim()).filter(Boolean)
const arrToStores = (a) => a.join(', ')

